/* Minimal iframeResizer contentWindow stub to avoid CDN fetches and Tracking Prevention prompts.
   This file intentionally does nothing sensitive and exists so any dynamic loader can find a same-origin copy.
*/
(function () {
  if (typeof window === 'undefined') return;
  // Provide a lightweight shim API expected by iframe-resizer consumers
  window.iFrameResizer = window.iFrameResizer || {};
  window.iFrameResizer.contentWindow = window.iFrameResizer.contentWindow || {};
  // no-op: keep interface compatibility
})();
